import 'package:flutter_bloc/flutter_bloc.dart';

// State is anything — often a sealed hierarchy for exhaustive matching
sealed class CounterState {}
class CounterInitial extends CounterState {}
class CounterValue extends CounterState { CounterValue(this.n); final int n; }

class CounterCubit extends Cubit<CounterState> {
  CounterCubit() : super(CounterInitial());

  int _count = 0;

  void increment() { _count++; emit(CounterValue(_count)); }
  void decrement() { _count--; emit(CounterValue(_count)); }
  void reset()     { _count = 0; emit(CounterValue(0)); }
}

// UI
BlocProvider(
  create: (_) => CounterCubit(),
  child: BlocBuilder<CounterCubit, CounterState>(
    builder: (ctx, s) => switch (s) {
      CounterInitial() => const Text('start'),
      CounterValue(:final n) => Text('$n'),
    },
  ),
);

// Elsewhere:
context.read<CounterCubit>().increment();
// no `CounterCubit.add(IncrementEvent())` ceremony.

import 'package:flutter_bloc/flutter_bloc.dart';

sealed class UserState {}
class UserLoading extends UserState {}
class UserLoaded extends UserState { UserLoaded(this.name); final String name; }
class UserError extends UserState { UserError(this.msg); final String msg; }

class UserCubit extends Cubit<UserState> {
  UserCubit(this._repo) : super(UserLoading());

  final UserRepository _repo;

  Future<void> load(int id) async {
    emit(UserLoading());
    try {
      emit(UserLoaded(await _repo.getName(id)));
    } catch (e) {
      emit(UserError(e.toString()));
    }
  }

  Future<void> refresh() async {
    if (state is UserLoaded) await load(1);   // implicit id — real app: pass it
  }
}

// UI
BlocConsumer<UserCubit, UserState>(
  listener: (ctx, s) {
    if (s is UserError) {
      ScaffoldMessenger.of(ctx).showSnackBar(SnackBar(content: Text(s.msg)));
    }
  },
  builder: (ctx, s) => switch (s) {
    UserLoading() => const CircularProgressIndicator(),
    UserLoaded(:final name) => Text('Hi, $name'),
    UserError() => const Text('Try again'),
  },
);

// Test:
